import React, { useState, useEffect } from 'react'; // Agregamos useEffect
import axios from 'axios';
import './App.css';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userRole, setUserRole] = useState(''); // Guardamos el rol (admin o vendedor)
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');

  // Función para cargar datos de la base de datos
  const cargarEstadisticas = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/stats');
      setStats(res.data);
    } catch (error) {
      console.log("Error cargando stats");
    }
  };

  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setIsLoggedIn(true);
        setUserRole(res.data.rol); // Guardamos el rol que viene de SQL
        cargarEstadisticas(); // Cargamos los números reales
      }
    } catch (error) {
      alert("Error al entrar");
    }
  };

  // ... (En el return del Dashboard, actualiza las tarjetas)

  // Dentro de la tarjeta de Estadísticas Rápidas:
  /*
  <div className="card">
    <h3>Estadísticas Rápidas</h3>
    <div className="card-content">
      <p>Total de Productos: {stats.total_productos}</p>
      <p>Valor Total: ${stats.valor_inventario}</p>
    </div>
  </div>
  */

  // Lógica de Admin:
  /*
  <nav className="nav-bar">
    {userRole === 'admin' && <span className="nav-link">Gestionar Productos (Solo Admin)</span>}
    <span className="nav-link">Registrar Movimientos</span>
  </nav>
  */
}
